  ('elementary-10ced7e2-moex-00217', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '依公務人員訓練進修法施行細則的定義，下列敘述何者錯誤？', '["訓練，指為因應業務需要，提升公務人員工作效能，由各機關（構）學校提供現職或未來職務所需知識 與技能之過程", "進修，指為配合組織發展或促進個人自我發展，由各機關（構）學校選送或由公務人員自行申請參加學 術或其他機關（構）學校學習或研究，以增進學識及汲取經驗之過程", "專題研究，指由各機關（構）學校選送或公務人員自行申請至國內外機關或政府立案之機構、學校從事 與業務有關之研究或實習", "入學進修，指由各機關（構）學校選送或公務人員自行申請至國內外政府立案之專科以上學校修習與業 務有關之學科"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "0d6660489e0e", "answer_pdf_sha1": "b09042515ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00218', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '公務人員福利措施是指下列何者？', '["工作報酬以外，政府為安定員工生活，激勵工作士氣所提供之升遷、考績或管理措施", "工作報酬以外，政府為安定員工生活，激勵工作士氣所提供之給與、照顧或服務措施", "工作報酬以外，政府為安定員工生活，激勵工作士氣所提供之考試、訓練或撫卹措施", "工作報酬以外，政府為安定員工生活，激勵工作士氣所提供之結社、保障或生活措施"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "0d6660489e0e", "answer_pdf_sha1": "b09042515ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00219', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '公務人員任職不滿1年，而連續任職已達6個月者應辦理：', '["另予考績", "年中考績", "年終考績", "個人考績"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "0d6660489e0e", "answer_pdf_sha1": "b09042515ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00220', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '某甲原先調到現行機關任職時，敘委任第一職等本俸四級，經過第1年另予考績和後2年年終考績後， 每次均獲「1個月俸給總額之一次獎金」，目前敘委任第一職等本俸六級。有關某甲之敘述，下列何者 正確？', '["過去3年考績為2年甲等1年丙等", "已取得委任第二職等的任用資格", "在現行機關的任職年資未滿2年6個月", "下一年度年終考績若是甲等，將可領取「2個月俸給總額之一次獎金」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "0d6660489e0e", "answer_pdf_sha1": "b09042515ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
